int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;
    if (k <= c)
        return c;
    else
        return k;
}

kernel void nw_kernel1(global int* reference,
                       global int* input_itemsets,
                       global int* output_itemsets,
                       local int* elem_23,
                       local int* item_16,
                       int max_cols,
                       int penalty,
                       int blk,
                       int block_width,
                       int worksize,
                       int offset_r,
                       int offset_c) {

    int elem_19 = get_global_id(0);

    if (elem_19 >= blk * BLOCK_SIZE)
        return;

    if (elem_19 >= blk)
        return;

    int item_11 = blk - 1 - elem_19;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            item_16[i * BLOCK_SIZE + j] = reference[max_cols * (item_11 * BLOCK_SIZE + i + 1) + elem_19 * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; i++) {
        for (int j = 0; j < BLOCK_SIZE + 1; j++) {
            elem_23[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (item_11 * BLOCK_SIZE + i) + elem_19 * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; i++) {
        for (int j = 1; j < BLOCK_SIZE + 1; j++) {
            elem_23[i * (BLOCK_SIZE + 1) + j] = maximum(
                elem_23[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + item_16[(i - 1) * BLOCK_SIZE + j - 1],
                elem_23[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
